#pragma once

#include <memory>
#include <stdexcept>
#include <vector>

#include <BinaryCodeWord/BinaryCodeWord.hpp>

class BinaryCodeGenMat {
public:
    // Empty, uninitialized matrix
    BinaryCodeGenMat() = default;

    // Supply rows (before initialize)
    void pushRow(const BinaryCodeWord& row);

    // Freeze staged rows into internal array (not vector)
    void initialize();

    bool initialized() const noexcept { return m_initialized; }

    int length() const;
    int numRows() const;
    BinaryCodeWord row(int i) const { return (*this)[i]; }

    // Access ORIGINAL supplied rows
    const BinaryCodeWord& operator[](int i) const;
    BinaryCodeWord& operator[](int i);

    // Codeword multiplied by Generator matrix
    friend BinaryCodeWord operator*(const BinaryCodeWord& u, const BinaryCodeGenMat& G);

    // Return NEW matrix in systematic form
    BinaryCodeGenMat getSystematic() const;

    void swapColumns(int c1, int c2);

private:
    bool m_initialized{false};
    int m_length{0};
    int m_numRows{0};

    // staging area
    std::vector<BinaryCodeWord> m_staging;

    // stored original rows
    std::unique_ptr<BinaryCodeWord[]> m_rows;

private:
    void requireInitialized() const;
    void requireValidIndex(int i) const;

    static void swapColumns(std::vector<BinaryCodeWord>& rows, int c1, int c2);
};

#pragma once

#include <memory>
#include <stdexcept>
#include <vector>

#include <BinaryCodeWord/BinaryCodeWord.hpp>

class BinaryCodeGenMat {
public:
    // Empty, uninitialized matrix
    BinaryCodeGenMat() = default;

    // Value semantics (deep copy of rows)
    BinaryCodeGenMat(const BinaryCodeGenMat& other);
    BinaryCodeGenMat& operator=(const BinaryCodeGenMat& other);
    BinaryCodeGenMat(BinaryCodeGenMat&& other) noexcept = default;
    BinaryCodeGenMat& operator=(BinaryCodeGenMat&& other) noexcept = default;
    virtual ~BinaryCodeGenMat() = default;

    // Supply rows (before initialize)
    void pushRow(const BinaryCodeWord& row);

    // Freeze staged rows into internal array (not vector)
    void initialize();

    bool initialized() const noexcept { return m_initialized; }

    int length() const;
    int numRows() const;
    BinaryCodeWord row(int i) const { return (*this)[i]; }

    // Access ORIGINAL supplied rows
    const BinaryCodeWord& operator[](int i) const;
    BinaryCodeWord& operator[](int i);

    // Codeword multiplied by Generator matrix
    friend BinaryCodeWord operator*(const BinaryCodeWord& u, const BinaryCodeGenMat& G);

    // Return NEW matrix in systematic form
    BinaryCodeGenMat getSystematic() const;

    // Return NEW matrix which is the transpose of this one.
    // If this is k x n (numRows x length), transpose is n x k.
    BinaryCodeGenMat transpose() const;

    // Matrix arithmetic over GF(2)
    BinaryCodeGenMat& operator+=(const BinaryCodeGenMat& rhs);
    BinaryCodeGenMat& operator*=(const BinaryCodeGenMat& rhs);

    friend BinaryCodeGenMat operator+(BinaryCodeGenMat lhs, const BinaryCodeGenMat& rhs) {
        lhs += rhs;
        return lhs;
    }
    friend BinaryCodeGenMat operator*(BinaryCodeGenMat lhs, const BinaryCodeGenMat& rhs) {
        lhs *= rhs;
        return lhs;
    }

    bool operator==(const BinaryCodeGenMat& rhs) const;
    bool operator!=(const BinaryCodeGenMat& rhs) const { return !(*this == rhs); }

    void swapColumns(int c1, int c2);

private:
    bool m_initialized{false};
    int m_length{0};
    int m_numRows{0};

    // staging area
    std::vector<BinaryCodeWord> m_staging;

    // stored original rows
    std::unique_ptr<BinaryCodeWord[]> m_rows;

private:
    void requireInitialized() const;
    void requireValidIndex(int i) const;

    static void swapColumns(std::vector<BinaryCodeWord>& rows, int c1, int c2);
};

// A square binary matrix is a generator matrix with length == numRows().
class BinarySquareMatrix : public BinaryCodeGenMat {
public:
    using BinaryCodeGenMat::BinaryCodeGenMat;

    // Computes (*this)^exp using successive squaring over GF(2).
    // exp must be >= 0.
    BinarySquareMatrix power(int exp) const;
};

// Identity matrix over GF(2)
class BinaryIdentityMatrix : public BinarySquareMatrix {
public:
    BinaryIdentityMatrix() = default;
    explicit BinaryIdentityMatrix(int size);

    void setSize(int size);
};

#include "BinaryCodeGenMat/BinaryCodeGenMat.hpp"

#include <algorithm>

void BinaryCodeGenMat::pushRow(const BinaryCodeWord& row) {
    if (m_initialized) {
        throw std::logic_error("BinaryCodeGenMat::pushRow: cannot push after initialize()");
    }
    if (!row.initialized()) {
        throw std::logic_error("BinaryCodeGenMat::pushRow: codeword is uninitialized");
    }
    m_staging.push_back(row);
}

void BinaryCodeGenMat::initialize() {
    if (m_initialized) {
        throw std::logic_error("BinaryCodeGenMat::initialize: already initialized");
    }
    if (m_staging.empty()) {
        throw std::logic_error("BinaryCodeGenMat::initialize: no rows supplied");
    }

    m_length = m_staging[0].length();
    for (const auto& r : m_staging) {
        if (r.length() != m_length) {
            throw std::invalid_argument("BinaryCodeGenMat::initialize: row length mismatch");
        }
    }

    m_numRows = static_cast<int>(m_staging.size());
    m_rows = std::make_unique<BinaryCodeWord[]>(static_cast<std::size_t>(m_numRows));
    for (int i = 0; i < m_numRows; ++i) {
        m_rows[i] = m_staging[i];
    }

    m_initialized = true;
}

int BinaryCodeGenMat::length() const {
    requireInitialized();
    return m_length;
}

int BinaryCodeGenMat::numRows() const {
    requireInitialized();
    return m_numRows;
}

const BinaryCodeWord& BinaryCodeGenMat::operator[](int i) const {
    requireInitialized();
    requireValidIndex(i);
    return m_rows[i];
}

BinaryCodeWord& BinaryCodeGenMat::operator[](int i) {
    requireInitialized();
    requireValidIndex(i);
    return m_rows[i];
}

BinaryCodeWord operator*(const BinaryCodeWord& lhs, const BinaryCodeGenMat& rhs){
    if (!lhs.initialized()){
        throw std::logic_error("Left-hand BinaryCodeWord is uninitialized");
    }
    rhs.requireInitialized();
    if (lhs.length() != rhs.numRows()) {
        throw std::invalid_argument("Length of BinaryCodeWord does not match number of rows in BinaryCodeGenMat");
    }
    BinaryCodeWord result(rhs.length());
    for (int row = 0; row < rhs.numRows(); ++row){
        if (lhs.getBit(row) == 1) {
            result += rhs[row];
        }
    }
    return result;
}

void BinaryCodeGenMat::swapColumns(int c1, int c2){
    requireInitialized();
    if (c1 < 0 || c1 >= m_length || c2 < 0 || c2 >= m_length) {
        throw std::out_of_range("Column index out of range");
    }
    if (c1 == c2) return;
    for (int i = 0; i < m_numRows; ++i) {
        m_rows[i].swap(c1, c2); // uses BinaryCodeWord::swap
    }
}

void BinaryCodeGenMat::swapColumns(std::vector<BinaryCodeWord>& rows, int c1, int c2) {
    if (c1 == c2) return;
    for (auto& r : rows) {
        r.swap(c1, c2); // uses BinaryCodeWord::swap
    }
}

BinaryCodeGenMat BinaryCodeGenMat::getSystematic() const {
    requireInitialized();

    std::vector<BinaryCodeWord> work;
    work.reserve(static_cast<std::size_t>(m_numRows));
    for (int i = 0; i < m_numRows; ++i) {
        work.push_back(m_rows[i]);
    }

    int pivotRow = 0;
    int pivotCol = 0;

    while (pivotRow < static_cast<int>(work.size()) && pivotCol < m_length) {
        int sel = -1;
        for (int r = pivotRow; r < static_cast<int>(work.size()); ++r) {
            if (work[r].getBit(pivotCol) == 1) {
                sel = r;
                break;
            }
        }

        if (sel == -1) {
            ++pivotCol;
            continue;
        }

        if (sel != pivotRow) {
            std::swap(work[sel], work[pivotRow]);
        }

        if (pivotCol != pivotRow) {
            swapColumns(work, pivotCol, pivotRow);
            pivotCol = pivotRow;
        }

        for (int r = 0; r < static_cast<int>(work.size()); ++r) {
            if (r == pivotRow) continue;
            if (work[r].getBit(pivotRow) == 1) {
                work[r] += work[pivotRow];
            }
        }

        ++pivotRow;
        ++pivotCol;
    }

    std::vector<BinaryCodeWord> reduced;
    for (auto& r : work) {
        if (!r.isZero()) {
            reduced.push_back(r);
        }
    }

    BinaryCodeGenMat sys;
    for (auto& r : reduced) {
        sys.pushRow(r);
    }
    sys.initialize();
    return sys;
}

void BinaryCodeGenMat::requireInitialized() const {
    if (!m_initialized) {
        throw std::logic_error("BinaryCodeGenMat: not initialized");
    }
}

void BinaryCodeGenMat::requireValidIndex(int i) const {
    if (i < 0 || i >= m_numRows) {
        throw std::out_of_range("BinaryCodeGenMat: row index out of range");
    }
}

#include "BinaryCodeGenMat/BinaryCodeGenMat.hpp"

#include <algorithm>

namespace {
BinaryCodeGenMat fromRows(const std::vector<BinaryCodeWord>& rows) {
    BinaryCodeGenMat M;
    for (const auto& r : rows) {
        M.pushRow(r);
    }
    M.initialize();
    return M;
}
}

BinaryCodeGenMat::BinaryCodeGenMat(const BinaryCodeGenMat& other)
    : m_initialized(other.m_initialized),
      m_length(other.m_length),
      m_numRows(other.m_numRows),
      m_staging(other.m_staging) {
    if (other.m_rows && other.m_numRows > 0) {
        m_rows = std::make_unique<BinaryCodeWord[]>(static_cast<std::size_t>(other.m_numRows));
        for (int i = 0; i < other.m_numRows; ++i) {
            m_rows[i] = other.m_rows[i];
        }
    }
}

BinaryCodeGenMat& BinaryCodeGenMat::operator=(const BinaryCodeGenMat& other) {
    if (this == &other) return *this;
    m_initialized = other.m_initialized;
    m_length = other.m_length;
    m_numRows = other.m_numRows;
    m_staging = other.m_staging;

    if (other.m_rows && other.m_numRows > 0) {
        m_rows = std::make_unique<BinaryCodeWord[]>(static_cast<std::size_t>(other.m_numRows));
        for (int i = 0; i < other.m_numRows; ++i) {
            m_rows[i] = other.m_rows[i];
        }
    } else {
        m_rows.reset();
    }
    return *this;
}

void BinaryCodeGenMat::pushRow(const BinaryCodeWord& row) {
    if (m_initialized) {
        throw std::logic_error("BinaryCodeGenMat::pushRow: cannot push after initialize()");
    }
    if (!row.initialized()) {
        throw std::logic_error("BinaryCodeGenMat::pushRow: codeword is uninitialized");
    }
    m_staging.push_back(row);
}

