        }
    }

    m_numRows = static_cast<int>(m_staging.size());
    m_rows = std::make_unique<BinaryCodeWord[]>(static_cast<std::size_t>(m_numRows));
    for (int i = 0; i < m_numRows; ++i) {
        m_rows[i] = m_staging[i];
    }

    m_initialized = true;
}

